   338→  // Validate the timeout, if present.
   339→  validateTimeout(options.timeout);
   340→
   341→  // Validate maxBuffer, if present.
   342→  validateMaxBuffer(options.maxBuffer);
   343→
   344→  options.killSignal = sanitizeKillSignal(options.killSignal);
   345→
   346→  const child = spawn(file, args, {
   347→    cwd: options.cwd,
   348→    env: options.env,
   349→    gid: options.gid,
   350→    shell: options.shell,
   351→    signal: options.signal,
   352→    uid: options.uid,
   353→    windowsHide: !!options.windowsHide,
   354→    windowsVerbatimArguments: !!options.windowsVerbatimArguments,
   355→  });
   356→
   357→  let encoding;
   358→  const _stdout = [];
   359→  const _stderr = [];
   360→  if (options.encoding !== 'buffer' && Buffer.isEncoding(options.encoding)) {
   361→    encoding = options.encoding;
   362→  } else {
   363→    encoding = null;
   364→  }
   365→  let stdoutLen = 0;
   366→  let stderrLen = 0;
   367→  let killed = false;
   368→  let exited = false;
   369→  let timeoutId;
   370→
   371→  let ex = null;
   372→
   373→  let cmd = file;
   374→
   375→  function exithandler(code, signal) {
   376→    if (exited) return;
   377→    exited = true;
   378→
   379→    if (timeoutId) {
   380→      clearTimeout(timeoutId);
   381→      timeoutId = null;
   382→    }
   383→
   384→    if (!callback) return;
   385→
   386→    // merge chunks
   387→    let stdout;
   388→    let stderr;
   389→    if (encoding ||
   390→      (
   391→        child.stdout?.readableEncoding
   392→      )) {
   393→      stdout = ArrayPrototypeJoin(_stdout, '');
   394→    } else {
   395→      stdout = Buffer.concat(_stdout);
   396→    }
   397→    if (encoding ||
   398→      (
   399→        child.stderr?.readableEncoding
   400→      )) {
   401→      stderr = ArrayPrototypeJoin(_stderr, '');
   402→    } else {
   403→      stderr = Buffer.concat(_stderr);
   404→    }
   405→
   406→    if (!ex && code === 0 && signal === null) {
   407→      callback(null, stdout, stderr);
   408→      return;
   409→    }
