   420→    ex.cmd = cmd;
   421→    callback(ex, stdout, stderr);
   422→  }
   423→
   424→  function errorhandler(e) {
   425→    ex = e;
   426→
   427→    if (child.stdout)
   428→      child.stdout.destroy();
   429→
   430→    if (child.stderr)
   431→      child.stderr.destroy();
   432→
   433→    exithandler();
   434→  }
   435→
   436→  function kill() {
   437→    if (child.stdout)
   438→      child.stdout.destroy();
   439→
   440→    if (child.stderr)
   441→      child.stderr.destroy();
   442→
   443→    killed = true;
   444→    try {
   445→      child.kill(options.killSignal);
   446→    } catch (e) {
   447→      ex = e;
   448→      exithandler();
   449→    }
   450→  }
   451→
   452→  if (options.timeout > 0) {
   453→    timeoutId = setTimeout(function delayedKill() {
   454→      kill();
   455→      timeoutId = null;
   456→    }, options.timeout);
   457→  }
   458→
   459→  if (child.stdout) {
   460→    if (encoding)
   461→      child.stdout.setEncoding(encoding);
   462→
   463→    child.stdout.on('data', function onChildStdout(chunk) {
   464→      // Do not need to count the length
   465→      if (options.maxBuffer === Infinity) {
   466→        ArrayPrototypePush(_stdout, chunk);
   467→        return;
   468→      }
   469→      const encoding = child.stdout.readableEncoding;
   470→      const length = encoding ?
   471→        Buffer.byteLength(chunk, encoding) :
   472→        chunk.length;
   473→      const slice = encoding ? StringPrototypeSlice :
   474→        (buf, ...args) => buf.slice(...args);
   475→      stdoutLen += length;
   476→
   477→      if (stdoutLen > options.maxBuffer) {
   478→        const truncatedLen = options.maxBuffer - (stdoutLen - length);
   479→        ArrayPrototypePush(_stdout, slice(chunk, 0, truncatedLen));
   480→
   481→        ex = new ERR_CHILD_PROCESS_STDIO_MAXBUFFER('stdout');
   482→        kill();
   483→      } else {
   484→        ArrayPrototypePush(_stdout, chunk);
   485→      }
   486→    });
   487→  }
   488→
   489→  if (child.stderr) {
   490→    if (encoding)
   491→      child.stderr.setEncoding(encoding);
   492→
   493→    child.stderr.on('data', function onChildStderr(chunk) {
   494→      // Do not need to count the length
   495→      if (options.maxBuffer === Infinity) {
   496→        ArrayPrototypePush(_stderr, chunk);
   497→        return;
   498→      }
   499→      const encoding = child.stderr.readableEncoding;
   500→      const length = encoding ?
   501→        Buffer.byteLength(chunk, encoding) :
   502→        chunk.length;
   503→      stderrLen += length;
   504→
   505→      if (stderrLen > options.maxBuffer) {
   506→        const truncatedLen = options.maxBuffer - (stderrLen - length);
   507→        ArrayPrototypePush(_stderr,
   508→                           chunk.slice(0, truncatedLen));
   509→
   510→        ex = new ERR_CHILD_PROCESS_STDIO_MAXBUFFER('stderr');
   511→        kill();
   512→      } else {
   513→        ArrayPrototypePush(_stderr, chunk);
   514→      }
   515→    });
   516→  }
