   530→function copyProcessEnvToEnv(env, name, optionEnv) {
   531→  if (process.env[name] &&
   532→      (!optionEnv ||
   533→       !ObjectPrototypeHasOwnProperty(optionEnv, name))) {
   534→    env[name] = process.env[name];
   535→  }
