   545→  if (ArrayIsArray(args)) {
   546→    args = ArrayPrototypeSlice(args);
   547→  } else if (args == null) {
   548→    args = [];
   549→  } else if (typeof args !== 'object') {
   550→    throw new ERR_INVALID_ARG_TYPE('args', 'object', args);
   551→  } else {
   552→    options = args;
   553→    args = [];
   554→  }
   555→
   556→  validateArgumentsNullCheck(args, 'args');
   557→
   558→  if (options === undefined)
   559→    options = kEmptyObject;
   560→  else
   561→    validateObject(options, 'options');
   562→
