   565→
   566→  // Validate the cwd, if present.
   567→  if (cwd != null) {
   568→    cwd = getValidatedPath(cwd, 'options.cwd');
   569→  }
   570→
   571→  // Validate detached, if present.
   572→  if (options.detached != null) {
   573→    validateBoolean(options.detached, 'options.detached');
   574→  }
   575→
   576→  // Validate the uid, if present.
   577→  if (options.uid != null && !isInt32(options.uid)) {
   578→    throw new ERR_INVALID_ARG_TYPE('options.uid', 'int32', options.uid);
   579→  }
   580→
   581→  // Validate the gid, if present.
   582→  if (options.gid != null && !isInt32(options.gid)) {
   583→    throw new ERR_INVALID_ARG_TYPE('options.gid', 'int32', options.gid);
   584→  }
   585→
   586→  // Validate the shell, if present.
   587→  if (options.shell != null &&
   588→      typeof options.shell !== 'boolean' &&
   589→      typeof options.shell !== 'string') {
   590→    throw new ERR_INVALID_ARG_TYPE('options.shell',
   591→                                   ['boolean', 'string'], options.shell);
   592→  }
   593→
   594→  // Validate argv0, if present.
   595→  if (options.argv0 != null) {
   596→    validateString(options.argv0, 'options.argv0');
