   995→  // At least 3 stdio will be created
   996→  // Don't concat() a new Array() because it would be sparse, and
   997→  // stdio.reduce() would skip the sparse elements of stdio.
   998→  // See https://stackoverflow.com/a/5501711/3561
   999→  while (stdio.length < 3) ArrayPrototypePush(stdio, undefined);
