  1036→      }
  1037→
  1038→      ipc = new Pipe(PipeConstants.IPC);
  1039→      ipcFd = i;
  1040→
  1041→      ArrayPrototypePush(acc, {
  1042→        type: 'pipe',
  1043→        handle: ipc,
  1044→        ipc: true,
  1045→      });
