  1061→
  1062→      ArrayPrototypePush(acc, {
  1063→        type: 'wrap',
  1064→        wrapType: getHandleWrapType(handle),
  1065→        handle: handle,
  1066→        _stdio: stdio,
  1067→      });
  1068→    } else if (isArrayBufferView(stdio) || typeof stdio === 'string') {
  1069→      if (!sync) {
