    99→  static uv_stream_t* StreamForWrap(Environment* env, Local<Object> stdio) {
   100→    Local<String> handle_key = env->handle_string();
   101→    // This property has always been set by JS land if we are in this code path.
   102→    Local<Object> handle =
   103→        stdio->Get(env->context(), handle_key).ToLocalChecked().As<Object>();
   104→
   105→    uv_stream_t* stream = LibuvStreamWrap::From(env, handle)->stream();
   106→    CHECK_NOT_NULL(stream);
   107→    return stream;
   108→  }
   109→
   110→  static void ParseStdioOptions(Environment* env,
   111→                                Local<Object> js_options,
   112→                                uv_process_options_t* options) {
   113→    Local<Context> context = env->context();
   114→    Local<String> stdio_key = env->stdio_string();
   115→    Local<Array> stdios =
   116→        js_options->Get(context, stdio_key).ToLocalChecked().As<Array>();
   117→
   118→    uint32_t len = stdios->Length();
   119→    options->stdio = new uv_stdio_container_t[len];
   120→    options->stdio_count = len;
   121→
   122→    for (uint32_t i = 0; i < len; i++) {
   123→      Local<Object> stdio =
   124→          stdios->Get(context, i).ToLocalChecked().As<Object>();
   125→      Local<Value> type =
   126→          stdio->Get(context, env->type_string()).ToLocalChecked();
   127→
   128→      if (type->StrictEquals(env->ignore_string())) {
   129→        options->stdio[i].flags = UV_IGNORE;
   130→      } else if (type->StrictEquals(env->pipe_string())) {
   131→        options->stdio[i].flags = static_cast<uv_stdio_flags>(
   132→            UV_CREATE_PIPE | UV_READABLE_PIPE | UV_WRITABLE_PIPE);
   133→        options->stdio[i].data.stream = StreamForWrap(env, stdio);
   134→      } else if (type->StrictEquals(env->overlapped_string())) {
   135→        options->stdio[i].flags = static_cast<uv_stdio_flags>(
   136→            UV_CREATE_PIPE | UV_READABLE_PIPE | UV_WRITABLE_PIPE |
   137→            UV_OVERLAPPED_PIPE);
   138→        options->stdio[i].data.stream = StreamForWrap(env, stdio);
   139→      } else if (type->StrictEquals(env->wrap_string())) {
   140→        options->stdio[i].flags = UV_INHERIT_STREAM;
   141→        options->stdio[i].data.stream = StreamForWrap(env, stdio);
   142→      } else {
   143→        Local<String> fd_key = env->fd_string();
   144→        Local<Value> fd_value = stdio->Get(context, fd_key).ToLocalChecked();
   145→        CHECK(fd_value->IsNumber());
   146→        int fd = static_cast<int>(fd_value.As<Integer>()->Value());
   147→        options->stdio[i].flags = UV_INHERIT_FD;
   148→        options->stdio[i].data.fd = fd;
   149→      }
   150→    }
