   331→ * @param {*} value
   332→ * @param {string} name
   333→ * @returns {asserts value is boolean[]}
   334→ */
   335→
   336→/** @type {validateBooleanArray} */
   337→const validateBooleanArray = hideStackFrames((value, name) => {
   338→  validateArray(value, name);
   339→  for (let i = 0; i < value.length; ++i) {
